import 'package:flutter/material.dart'; import 'package:go_router/go_router.dart'; import '../theme.dart';
class GlassCard extends StatelessWidget{final Widget child; final EdgeInsets padding; const GlassCard({super.key,required this.child,this.padding=const EdgeInsets.all(16)}); @override Widget build(BuildContext c)=>Container(padding:padding,decoration:BoxDecoration(color:Colors.white.withValues(alpha:.82),borderRadius:BorderRadius.circular(16),border:Border.all(color:Colors.white.withValues(alpha:.55)),boxShadow:[BoxShadow(color:Colors.black.withValues(alpha:.05),blurRadius:20,offset:const Offset(0,4))]),child:child);}
class Shell extends StatelessWidget{final Widget child; final int index; const Shell({super.key,required this.child,required this.index}); @override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('Mesuji Bergerak'),actions:[IconButton(onPressed:()=>c.go('/notifications'),icon:const Icon(Icons.notifications,color:primary))]),body:child,bottomNavigationBar:NavigationBar(selectedIndex:index,onDestinationSelected:(i){final paths=['/home','/aspirasi','/ai','/market','/profile']; c.go(paths[i]);},destinations:const [NavigationDestination(icon:Icon(Icons.home_outlined),selectedIcon:Icon(Icons.home),label:'Home'),NavigationDestination(icon:Icon(Icons.forum_outlined),label:'Aspirasi'),NavigationDestination(icon:Icon(Icons.smart_toy_outlined),selectedIcon:Icon(Icons.smart_toy),label:'AI'),NavigationDestination(icon:Icon(Icons.storefront_outlined),label:'UMKM'),NavigationDestination(icon:Icon(Icons.person_outline),label:'Profile')]));}
class SectionTitle extends StatelessWidget{final String text; const SectionTitle(this.text,{super.key}); @override Widget build(BuildContext c)=>Text(text,style:const TextStyle(fontFamily:'Plus Jakarta Sans',fontSize:20,fontWeight:FontWeight.w700,color:onSurface));}
